const webhookData = $('Webhook Meta Cloud API').first().json;
const entry = webhookData.body.entry[0];
const changes = entry.changes[0].value;
const message = changes.messages[0];
const messageType = message.type;

let userMessage = '';
let phoneNumber = message.from;
let pushName = changes.contacts[0]?.profile?.name || 'Usuario';

if (messageType === 'text') {
  userMessage = message.text.body;
} else if (messageType === 'audio') {
  try {
    const whisperItems = $('Transcribir con Whisper').all();
    if (whisperItems && whisperItems.length > 0) {
      const whisperJson = whisperItems[0].json;
      userMessage = whisperJson.text || whisperJson.transcription || '[Audio sin transcripción]';
    } else {
      userMessage = '[No se pudo transcribir el audio]';
    }
  } catch (e) {
    userMessage = '[Error al transcribir audio: ' + e.message + ']';
  }
}

// Calcular calendario de referencia (3 semanas)
// FIX: Usar SOLO Luxon para todo, sin mezclar con new Date() que usa la zona del server
const dias = ['Domingo', 'Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado'];
const meses = ['enero', 'febrero', 'marzo', 'abril', 'mayo', 'junio', 'julio', 'agosto', 'septiembre', 'octubre', 'noviembre', 'diciembre'];

// Hoy en Paraguay usando SOLO Luxon (no new Date)
const paraguayTime = DateTime.now().setZone('America/Asuncion');
const hoyLuxon = paraguayTime.startOf('day');

let calendario = '';
for (let i = 0; i < 21; i++) {
  const d = hoyLuxon.plus({ days: i });
  const diaSemana = dias[d.weekday % 7]; // Luxon: 1=Monday...7=Sunday, convertir a 0=Sunday
  const fecha = d.day;
  const mes = meses[d.month - 1]; // Luxon months are 1-indexed
  const yyyy = d.year;
  const fechaISO = d.toFormat('yyyy-MM-dd');
  const marca = i === 0 ? ' ← HOY' : '';
  calendario += '- ' + diaSemana + ' ' + fecha + ' de ' + mes + ' ' + yyyy + ' (' + fechaISO + ')' + marca + '\n';
}

const fechaHoy = dias[paraguayTime.weekday % 7] + ' ' + paraguayTime.day + ' de ' + meses[paraguayTime.month - 1] + ' de ' + paraguayTime.year;
const horaActual = paraguayTime.toFormat('HH:mm');


// Leer configuración del panel
let configPanel = {};
try {
  const configItems = $('Leer Config Panel').all();
  if (configItems && configItems.length > 0) {
    configPanel = configItems[0].json;
  }
} catch (e) {
  configPanel = {};
}

// === RATE LIMIT: 12 mensajes por minuto ===
const mensajesUltimoMinuto = parseInt(configPanel.mensajes_ultimo_minuto) || 0;
if (mensajesUltimoMinuto >= 12) {
  // Supero el limite, ignorar mensaje silenciosamente
  return [];
}


// Generar tabla de servicios desde la config
let tablaServicios = '';
const serviciosConfig = configPanel.servicios || [];
if (serviciosConfig.length > 0) {
  tablaServicios = '| Servicio | Duración | Precio |\n|----------|----------|--------|\n';
  serviciosConfig.forEach(s => {
    const precio = s.precio ? s.precio.toLocaleString('es-PY') + ' PYG' : 'Consultar';
    tablaServicios += '| ' + s.nombre + ' | ' + s.duracion + ' min | ' + precio + ' |\n';
  });
} else {
  tablaServicios = 'No hay servicios configurados aún.';
}

// Generar horarios legibles
let horariosTexto = '';
const horariosConfig = configPanel.horarios || {};
const diasOrden = ['lunes', 'martes', 'miercoles', 'jueves', 'viernes', 'sabado', 'domingo'];
const diasLabelConfig = { lunes: 'Lunes', martes: 'Martes', miercoles: 'Miércoles', jueves: 'Jueves', viernes: 'Viernes', sabado: 'Sábado', domingo: 'Domingo' };
diasOrden.forEach(d => {
  const h = horariosConfig[d];
  if (h) {
    horariosTexto += diasLabelConfig[d] + ': ' + (h.cerrado ? 'Cerrado' : h.abre + ' - ' + h.cierra) + '\n';
  }
});


// === SALUDO INTELIGENTE BASADO EN TIEMPO ===
const minutosDesdeMensaje = configPanel.minutos_desde_ultimo;
let tipoSaludo = 'saludo_completo';
let descripcionTiempo = '';

if (minutosDesdeMensaje === null || minutosDesdeMensaje === undefined) {
  tipoSaludo = 'primera_vez';
  descripcionTiempo = 'Es la primera vez que escribe o no hay registro previo';
} else {
  const minutos = parseFloat(minutosDesdeMensaje);
  if (minutos < 30) {
    tipoSaludo = 'continuar';
    descripcionTiempo = 'Hace menos de 30 minutos que hablaron';
  } else if (minutos < 240) {
    const horas = Math.floor(minutos / 60);
    const mins = Math.floor(minutos % 60);
    tipoSaludo = 'saludo_corto';
    descripcionTiempo = 'Ultima conversacion hace ' + (horas > 0 ? horas + 'h ' : '') + mins + ' minutos';
  } else {
    const horas = Math.floor(minutos / 60);
    const dias = Math.floor(horas / 24);
    tipoSaludo = 'saludo_completo';
    if (dias > 0) {
      descripcionTiempo = 'Ultima conversacion hace ' + dias + ' dia(s)';
    } else {
      descripcionTiempo = 'Ultima conversacion hace ' + horas + ' horas';
    }
  }
}

const instanceName = $('Validar Instance Name').first().json.instanceName;

return [{
  json: {
    chatInput: userMessage,
    sessionId: phoneNumber,
    phoneNumber: phoneNumber,
    pushName: pushName,
    instanceName: instanceName,
    messageType: messageType,
    timestamp: new Date().toISOString(),
    fechaHoy: fechaHoy,
    horaActual: horaActual,
    calendario: calendario,
    configPanel: configPanel,
    tablaServicios: tablaServicios,
    horariosTexto: horariosTexto,
    nombreClinica: configPanel.nombre_clinica || 'Clínica Dental',
    nombreBot: configPanel.nombre_bot || 'Sofía',
    direccionClinica: configPanel.direccion || '',
    telefonoClinica: configPanel.telefono || '',
    emailClinica: configPanel.email || '',
    promptSistema: configPanel.prompt_sistema || '',
    mensajeBienvenida: configPanel.mensaje_bienvenida || '',
    clinicaId: configPanel.clinica_id || null,
    tipoSaludo: tipoSaludo,
    descripcionTiempo: descripcionTiempo
  }
}];

