return [{ json: { phoneNumber, instanceName, message: '¡Hola! 😊 Por el momento solo puedo leer mensajes de texto y audios. Si necesitas ayuda con una cita, por favor escríbeme un mensaje de texto. ¡Gracias!' } }];

const error = $input.all()[0].json;
return [{ json: { subject: '[ERROR] Clinica Dental - Recepcionista WhatsApp Meta Cloud API', message: 'Error en workflow:
Nodo: ' + (error.execution?.error?.node?.name || 'Desconocido') + '
Error: ' + (error.execution?.error?.message || JSON.stringify(error)) + '
Timestamp: ' + new Date().toISOString() + '
Execution ID: ' + (error.execution?.id || 'N/A') } }];

const phoneNumberId = $('Webhook Meta Cloud API').first().json.body.entry[0].changes[0].value.metadata.phone_number_id || '';
if (!phoneNumberId) {
  throw new Error('phone_number_id no encontrado en webhook de Meta');
}
// Map phone_number_id to instance name for clinic lookup
return [{ json: { instanceName: 'clinica-whatsapp-business', phoneNumberId } }];
